/*
  DilAvatar v15 — BEDEN KESİN SABİT
  ---------------------------------
  v14'te beden hareket ediyor gibi görünüyordu. Bu sürümde:
  - Gövde/ceket/arka plan tek sabit base kare olarak kalır.
  - Konuşma sırasında otomatik baş sallama KAPALI gelir.
  - Baş hareketi açılsa bile sadece çok küçük yüz maskesi hareket eder.
  - El/saç düzeltme kareleri tam resim olarak değil, transparan el/kol katmanı olarak gelir.
  - Böylece gövde ikinci kez çizilip zıplamaz.

  API:
    DilAvatar.mount(elementIdVeyaEleman, options?)
    DilAvatar.speakText(text, durationMs?)
    DilAvatar.setMouth(shape)
    DilAvatar.blink()
    DilAvatar.fixHair(true)
    DilAvatar.thinking(true|false)
    DilAvatar.stop()
    DilAvatar.setHeadMotion(true|false)
    DilAvatar.setAutoHair(true|false)
*/
(function(global) {
  "use strict";

  var STORAGE_KEY = "DilAvatar.frame.v15.settings";
  var FR = {"rest": "data:image/webp;base64,", "slight": "data:image/webp;base64,", "half": "data:image/webp;base64,", "mid": "data:image/webp;base64,", "open": "data:image/webp;base64,", "round": "data:image/webp;base64,", "wide": "data:image/webp;base64,", "blinkHalf": "data:image/webp;base64,", "blink": "data:image/webp;base64,", "handDown": "data:image/webp;base64,", "handNear": "data:image/webp;base64,", "handTouch": "data:image/webp;base64,"};

  var state = {
    host: null,
    root: null,
    frame: null,
    baseImg: null,
    faceStage: null,
    faceImg: null,
    handImg: null,

    currentFrame: "rest",
    lastSpeechFrame: "rest",

    speaking: false,
    thinking: false,
    hairActive: false,

    // Kritik: varsayılan kapalı. Bedenin yüzüyormuş gibi görünmesi engellenir.
    headMotion: false,
    autoHair: false,

    motionMode: "idle",

    speechTimer: null,
    thinkingTimer: null,
    blinkTimer: null,
    blinkSequenceTimer: null,
    hairTimer: null,
    autoHairTimer: null,
    motionRaf: null,

    opts: {
      size: 300,
      borderColor: "#2dd4bf",
      showMiniControls: false
    }
  };

  function safeGet(key, fallback) {
    try {
      var v = global.localStorage && global.localStorage.getItem(key);
      return v == null ? fallback : v;
    } catch(e) {
      return fallback;
    }
  }

  function safeSet(key, value) {
    try {
      if (global.localStorage) global.localStorage.setItem(key, value);
    } catch(e) {}
  }

  function loadSettings() {
    try {
      var saved = JSON.parse(safeGet(STORAGE_KEY, "{}") || "{}");
      if (typeof saved.headMotion === "boolean") state.headMotion = saved.headMotion;
      if (typeof saved.autoHair === "boolean") state.autoHair = saved.autoHair;
    } catch(e) {}
  }

  function saveSettings() {
    safeSet(STORAGE_KEY, JSON.stringify({
      headMotion: state.headMotion,
      autoHair: state.autoHair
    }));
  }

  function injectCss() {
    if (document.getElementById("dil-avatar-v15-style")) return;

    var css = `
      .dil-avatar-v15 {
        --da-border:#2dd4bf;
        width:100%;
        max-width:var(--da-size, 300px);
        min-width:120px;
        margin:0 auto;
        font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;
        color:#e5e7eb;
        user-select:none;
      }
      .dil-avatar-v15-frame {
        width:100%;
        aspect-ratio:1/1;
        position:relative;
        overflow:hidden;
        border-radius:50%;
        background:#0b1120;
        border:4px solid var(--da-border);
        box-shadow:0 18px 38px rgba(0,0,0,.28), inset 0 0 0 1px rgba(255,255,255,.08);
        transform:translateZ(0);
      }
      .dil-avatar-v15-layer {
        position:absolute;
        inset:0;
        width:100%;
        height:100%;
        object-fit:cover;
        object-position:center center;
        display:block;
        pointer-events:none;
        -webkit-user-drag:none;
      }
      .dil-avatar-v15-face {
        position:absolute;
        inset:0;
        width:100%;
        height:100%;
        transform-origin:50% 38%;
        will-change:transform;
        /*
          Çok dar yüz maskesi:
          Sadece göz-burun-ağız-sakalın üst kısmı değişir.
          Ceket, omuz, göğüs, gömlek bu katmanda görünmez.
        */
        clip-path:ellipse(25% 30% at 50% 39%);
      }
      .dil-avatar-v15-hand {
        position:absolute;
        inset:0;
        width:100%;
        height:100%;
        object-fit:cover;
        object-position:center center;
        display:none;
        pointer-events:none;
        -webkit-user-drag:none;
      }
      .dil-avatar-v15-mini {
        margin:10px auto 0;
        display:flex;
        gap:5px;
        align-items:center;
        justify-content:center;
        flex-wrap:wrap;
      }
      .dil-avatar-v15-mini button {
        border:0;
        border-radius:10px;
        padding:6px 8px;
        cursor:pointer;
        font-weight:800;
        font-size:11px;
        color:white;
        background:#2563eb;
      }
      .dil-avatar-v15-mini button.secondary {
        background:#1e293b;
        color:#dbeafe;
      }
    `;

    var style = document.createElement("style");
    style.id = "dil-avatar-v15-style";
    style.textContent = css;
    document.head.appendChild(style);
  }

  function preloadFrames() {
    Object.keys(FR).forEach(function(k) {
      var im = new Image();
      im.src = FR[k];
    });
  }

  function mount(target, options) {
    loadSettings();
    injectCss();
    preloadFrames();

    var host = typeof target === "string" ? document.getElementById(target) : target;
    if (!host) throw new Error("DilAvatar.mount: hedef eleman bulunamadı.");

    state.opts = Object.assign({}, state.opts, options || {});
    host.innerHTML = "";

    var root = document.createElement("div");
    root.className = "dil-avatar-v15";
    root.style.setProperty("--da-size", (state.opts.size || 300) + "px");
    root.style.setProperty("--da-border", state.opts.borderColor || "#2dd4bf");

    var frame = document.createElement("div");
    frame.className = "dil-avatar-v15-frame";

    // Sabit gövde: hiçbir zaman değişmez, hiçbir zaman transform edilmez.
    var baseImg = document.createElement("img");
    baseImg.className = "dil-avatar-v15-layer";
    baseImg.alt = "DilAvatar sabit beden";
    baseImg.src = FR.rest;

    // Hareketli konuşma sadece yüz maskesinde olur.
    var faceStage = document.createElement("div");
    faceStage.className = "dil-avatar-v15-face";

    var faceImg = document.createElement("img");
    faceImg.className = "dil-avatar-v15-layer";
    faceImg.alt = "DilAvatar hareketli yüz";
    faceImg.src = FR.rest;

    // El/kol transparan katman. Gövdeyi taşımaz.
    var handImg = document.createElement("img");
    handImg.className = "dil-avatar-v15-hand";
    handImg.alt = "DilAvatar saç düzeltme eli";
    handImg.src = FR.handDown;

    faceStage.appendChild(faceImg);
    frame.appendChild(baseImg);
    frame.appendChild(faceStage);
    frame.appendChild(handImg);
    root.appendChild(frame);

    if (state.opts.showMiniControls) {
      var mini = document.createElement("div");
      mini.className = "dil-avatar-v15-mini";
      mini.innerHTML = `
        <button type="button" data-da-act="speak">Konuş</button>
        <button type="button" data-da-act="hair" class="secondary">Saç</button>
        <button type="button" data-da-act="blink" class="secondary">Göz</button>
        <button type="button" data-da-act="stop" class="secondary">Dur</button>
      `;
      mini.addEventListener("click", function(ev) {
        var b = ev.target.closest("button");
        if (!b) return;
        var act = b.getAttribute("data-da-act");
        if (act === "speak") speakText("merhaba bugün ingilizce çalışıyoruz", 3200);
        if (act === "hair") fixHair(true);
        if (act === "blink") blink();
        if (act === "stop") stop();
      });
      root.appendChild(mini);
    }

    host.appendChild(root);

    state.host = host;
    state.root = root;
    state.frame = frame;
    state.baseImg = baseImg;
    state.faceStage = faceStage;
    state.faceImg = faceImg;
    state.handImg = handImg;

    showFrame("rest");
    setMotionMode("idle");
    scheduleBlink();
    scheduleAutoHair();

    return root;
  }

  function showFrame(name, rememberSpeech) {
    if (!FR[name]) name = "rest";
    if (!state.faceImg) return;

    state.currentFrame = name;
    state.faceImg.src = FR[name];

    if (rememberSpeech !== false && name !== "blink" && name !== "blinkHalf" && name.indexOf("hand") !== 0) {
      state.lastSpeechFrame = name;
    }
  }

  function mouthToFrame(shape) {
    switch(shape) {
      case "rest":
      case "closed": return "rest";
      case "slight": return "slight";
      case "half": return "half";
      case "mid": return "mid";
      case "open": return "open";
      case "round": return "round";
      case "wide": return "wide";
      case "teeth": return "mid";
      default: return "rest";
    }
  }

  function setMouth(shape) {
    if (state.hairActive) return;
    showFrame(mouthToFrame(shape));
  }

  function visemeForChar(ch) {
    ch = String(ch || "").toLocaleLowerCase("tr-TR");

    if (ch === "a" || ch === "â") return "open";
    if (ch === "e") return "wide";
    if (ch === "o" || ch === "u") return "round";
    if (ch === "ı" || ch === "i" || ch === "ü" || ch === "ö" || ch === "y") return "wide";
    if (ch === "m" || ch === "b" || ch === "p") return "closed";
    if (ch === "f" || ch === "v") return "teeth";
    if (/\s/.test(ch)) return "rest";

    if ("çcğhjklmnprsştzqxw".indexOf(ch) >= 0) return "slight";
    return "rest";
  }

  function frameForChar(ch, index) {
    var f = mouthToFrame(visemeForChar(ch));
    if (f === "slight" && index % 3 === 0) f = "half";
    return f;
  }

  function clearTimeoutSafe(t) {
    if (t) clearTimeout(t);
    return null;
  }

  function clearIntervalSafe(t) {
    if (t) clearInterval(t);
    return null;
  }

  function speakText(text, durationMs) {
    stopSpeechOnly();

    text = String(text || "");
    var chars = Array.prototype.slice.call(text);

    if (!chars.length) {
      showFrame("rest");
      setMotionMode("idle");
      return;
    }

    state.speaking = true;
    state.hairActive = false;
    hideHand();

    // Konuşurken beden ve kafa yüzmez. Sadece yüz karesi değişir.
    setMotionMode("talk");

    var total = Number(durationMs);
    var per = total && isFinite(total) ? total / chars.length : 110;
    per = Math.max(60, Math.min(150, per));

    var i = 0;
    function step() {
      if (!state.speaking || i >= chars.length) {
        state.speaking = false;
        showFrame("rest");
        setMotionMode("idle");
        scheduleAutoHair();
        return;
      }

      showFrame(frameForChar(chars[i], i));
      i += 1;
      state.speechTimer = setTimeout(step, per);
    }

    step();
  }

  function stopSpeechOnly() {
    state.speechTimer = clearTimeoutSafe(state.speechTimer);
    state.speaking = false;
  }

  function blink() {
    if (!state.faceImg || state.hairActive) return;

    var back = state.lastSpeechFrame || "rest";
    state.blinkSequenceTimer = clearTimeoutSafe(state.blinkSequenceTimer);

    showFrame("blinkHalf", false);
    state.blinkSequenceTimer = setTimeout(function() {
      showFrame("blink", false);
      state.blinkSequenceTimer = setTimeout(function() {
        showFrame("blinkHalf", false);
        state.blinkSequenceTimer = setTimeout(function() {
          showFrame(back, false);
        }, 70);
      }, 85);
    }, 70);
  }

  function scheduleBlink() {
    state.blinkTimer = clearTimeoutSafe(state.blinkTimer);
    var next = 2700 + Math.random() * 3400;
    state.blinkTimer = setTimeout(function() {
      blink();
      scheduleBlink();
    }, next);
  }

  function showHand(name) {
    if (!state.handImg || !FR[name]) return;
    state.handImg.src = FR[name];
    state.handImg.style.display = "block";
  }

  function hideHand() {
    if (state.handImg) state.handImg.style.display = "none";
  }

  function fixHair(force) {
    if (!state.handImg) return;
    if (state.speaking && !force) return;

    state.hairActive = true;
    state.speaking = false;
    state.speechTimer = clearTimeoutSafe(state.speechTimer);

    // Yüz sabit kalır, sadece transparan el/kol katmanı oynar.
    showFrame("rest", false);
    setMotionMode("idle");

    var seq = [
      ["handDown", 130],
      ["handNear", 170],
      ["handTouch", 260],
      ["handNear", 170],
      ["handDown", 130],
      ["rest", 90]
    ];

    var i = 0;
    state.hairTimer = clearTimeoutSafe(state.hairTimer);

    function step() {
      if (i >= seq.length) {
        state.hairActive = false;
        hideHand();
        showFrame("rest", false);
        scheduleAutoHair();
        return;
      }

      var frameName = seq[i][0];

      if (frameName === "rest") {
        hideHand();
      } else {
        showHand(frameName);
      }

      state.hairTimer = setTimeout(step, seq[i][1]);
      i += 1;
    }

    step();
  }

  function scheduleAutoHair() {
    state.autoHairTimer = clearTimeoutSafe(state.autoHairTimer);
    if (!state.autoHair) return;

    var next = 26000 + Math.random() * 22000;
    state.autoHairTimer = setTimeout(function() {
      if (!state.speaking && !state.thinking && !state.hairActive) fixHair(true);
      scheduleAutoHair();
    }, next);
  }

  function thinking(on) {
    state.thinking = !!on;
    state.thinkingTimer = clearIntervalSafe(state.thinkingTimer);

    if (!on) {
      showFrame("rest");
      setMotionMode("idle");
      return;
    }

    setMotionMode("think");
    var flip = false;

    state.thinkingTimer = setInterval(function() {
      if (state.hairActive) return;
      flip = !flip;
      showFrame(flip ? "slight" : "rest");
    }, 680);
  }

  function setMotionMode(mode) {
    state.motionMode = mode || "idle";
    startMotionLoop();
  }

  function startMotionLoop() {
    if (state.motionRaf) return;

    function loop() {
      state.motionRaf = requestAnimationFrame(loop);
      applyHeadMotion();
    }

    state.motionRaf = requestAnimationFrame(loop);
  }

  function applyHeadMotion() {
    if (!state.faceStage) return;

    // Varsayılan: kesinlikle sıfır hareket.
    if (!state.headMotion) {
      state.faceStage.style.transform = "translate3d(0,0,0) rotate(0deg) scale(1)";
      return;
    }

    // Kullanıcı açıkça açarsa bile sadece yüz maskesi çok mikro oynar.
    var t = performance.now();
    var x = 0, y = 0, r = 0, s = 1;

    if (state.motionMode === "talk") {
      x = Math.sin(t * 0.0050) * 0.55;
      y = Math.sin(t * 0.0062) * 0.35;
      r = Math.sin(t * 0.0038) * 0.12;
      s = 1.0006;
    } else if (state.motionMode === "think") {
      x = Math.sin(t * 0.0020) * 0.5;
      y = Math.sin(t * 0.0024) * 0.25;
      r = Math.sin(t * 0.0018) * 0.14;
      s = 1.0005;
    }

    state.faceStage.style.transform =
      "translate3d(" + x.toFixed(2) + "px," + y.toFixed(2) + "px,0) " +
      "rotate(" + r.toFixed(3) + "deg) " +
      "scale(" + s.toFixed(4) + ")";
  }

  function stop() {
    stopSpeechOnly();
    state.thinking = false;
    state.hairActive = false;
    state.thinkingTimer = clearIntervalSafe(state.thinkingTimer);
    state.hairTimer = clearTimeoutSafe(state.hairTimer);
    state.blinkSequenceTimer = clearTimeoutSafe(state.blinkSequenceTimer);
    hideHand();
    showFrame("rest");
    setMotionMode("idle");
  }

  function setHeadMotion(on) {
    state.headMotion = !!on;
    saveSettings();
    applyHeadMotion();
  }

  function setAutoHair(on) {
    state.autoHair = !!on;
    saveSettings();
    scheduleAutoHair();
  }

  function setGender(g) {
    return "erkek";
  }

  function getGender() {
    return "erkek";
  }

  function getFrameNames() {
    return Object.keys(FR).slice();
  }

  global.DilAvatar = {
    mount: mount,
    speakText: speakText,
    setMouth: setMouth,
    blink: blink,
    fixHair: fixHair,
    thinking: thinking,
    stop: stop,
    setHeadMotion: setHeadMotion,
    setAutoHair: setAutoHair,
    setGender: setGender,
    getGender: getGender,
    visemeForChar: visemeForChar,
    showFrame: showFrame,
    showHand: showHand,
    hideHand: hideHand,
    getFrameNames: getFrameNames
  };

})(window);
